+    sendInitialRequest: async () => {
+      if (!getInitialResponse) {
+        throw new Error("getInitialResponse is required when initializing a new poller");
+      }
+      initialResponse = await getInitialResponse();
+      return getLroResponse(initialResponse, expectedStatuses);
+    },
+    sendPollRequest: async (
+      path: string,
+      pollOptions?: {
+        abortSignal?: AbortSignalLike;
+      },
+    ) => {
+      // The poll request would both listen to the user provided abort signal and the poller's own abort signal
+      function abortListener(): void {
+        pollAbortController.abort();
+      }
+      const abortSignal = pollAbortController.signal;
+      if (options.abortSignal?.aborted) {
+        pollAbortController.abort();
+      } else if (pollOptions?.abortSignal?.aborted) {
+        pollAbortController.abort();
+      } else if (!abortSignal.aborted) {
+        options.abortSignal?.addEventListener("abort", abortListener, {
+          once: true,
+        });
+        pollOptions?.abortSignal?.addEventListener("abort", abortListener, {
+          once: true,
+        });
+      }
+      let response;
+      try {
+        const pollingPath = apiVersion ? addApiVersionToUrl(path, apiVersion) : path;
+        response = await client.pathUnchecked(pollingPath).get({ abortSignal });
+      } finally {
+        options.abortSignal?.removeEventListener("abort", abortListener);
+        pollOptions?.abortSignal?.removeEventListener("abort", abortListener);
+      }
+
+      return getLroResponse(response as TResponse, expectedStatuses);
+    },
+  };
+  return createHttpPoller(poller, {
+    intervalInMs: options?.updateIntervalInMs,
+    resourceLocationConfig: options?.resourceLocationConfig,
+    restoreFrom: options?.restoreFrom,
+    processResult: (result: unknown) => {
+      return processResponseBody(result as TResponse);
+    },
+  });
+}
+/**
+ * Converts a Rest Client response to a response that the LRO implementation understands
+ * @param response - a rest client http response
+ * @param deserializeFn - deserialize function to convert Rest response to modular output
+ * @returns - An LRO response that the LRO implementation understands
+ */
+function getLroResponse<TResponse extends PathUncheckedResponse>(
+  response: TResponse,
+  expectedStatuses: string[],
+): OperationResponse<TResponse> {
+  if (!expectedStatuses.includes(response.status)) {
+    throw createRestError(response);
+  }
+
+  return {
+    flatResponse: response,
+    rawResponse: {
+      ...response,
+      statusCode: Number.parseInt(response.status),
+      body: response.body,
+    },
+  };
+}
+
+/**
+ * Adds the api-version query parameter on a URL if it's not present.
+ * @param url - the URL to modify
+ * @param apiVersion - the API version to set
+ * @returns - the URL with the api-version query parameter set
+ */
+function addApiVersionToUrl(url: string, apiVersion: string): string {
+  // The base URL is only used for parsing and won't appear in the returned URL
+  const urlObj = new URL(url, "https://microsoft.com");
+  if (!urlObj.searchParams.get("api-version")) {
+    // Append one if there is no apiVersion
+    return `${url}${
+      Array.from(urlObj.searchParams.keys()).length > 0 ? "&" : "?"
+    }api-version=${apiVersion}`;
+  }
+  return url;
+}"},{"filename":"sdk/horizondb/arm-horizondb/src/static-helpers/simplePollerHelpers.ts","status":"added","additions":119,"changes":119,"patch":"@@ -0,0 +1,119 @@
+// Copyright (c) Microsoft Corporation.
+// Licensed under the MIT License.
+
+import type { PollerLike, OperationState, CancelOnProgress } from "@azure/core-lro";
+import type { AbortSignalLike } from "@azure/abort-controller";
+
+/**
+ * A simple poller that can be used to poll a long running operation.
+ */
+export interface SimplePollerLike<TState extends OperationState<TResult>, TResult> {
+  /**
+   * Returns true if the poller has finished polling.
+   */
+  isDone(): boolean;
+  /**
+   * Returns the state of the operation.
+   */
+  getOperationState(): TState;
+  /**
+   * Returns the result value of the operation,
+   * regardless of the state of the poller.
+   * It can return undefined or an incomplete form of the final TResult value
+   * depending on the implementation.
+   */
+  getResult(): TResult | undefined;
+  /**
+   * Returns a promise that will resolve once a single polling request finishes.
+   * It does this by calling the update method of the Poller's operation.
+   */
+  poll(options?: { abortSignal?: AbortSignalLike }): Promise<TState>;
+  /**
+   * Returns a promise that will resolve once the underlying operation is completed.
+   */
+  pollUntilDone(pollOptions?: { abortSignal?: AbortSignalLike }): Promise<TResult>;
+  /**
+   * Invokes the provided callback after each polling is completed,
+   * sending the current state of the poller's operation.
+   *
+   * It returns a method that can be used to stop receiving updates on the given callback function.
+   */
+  onProgress(callback: (state: TState) => void): CancelOnProgress;
+
+  /**
+   * Returns a promise that could be used for serialized version of the poller's operation
+   * by invoking the operation's serialize method.
+   */
+  serialize(): Promise<string>;
+
+  /**
+   * Wait the poller to be submitted.
+   */
+  submitted(): Promise<void>;
+
+  /**
+   * Returns a string representation of the poller's operation. Similar to serialize but returns a string.
+   * @deprecated Use serialize() instead.
+   */
+  toString(): string;
+
+  /**
+   * Stops the poller from continuing to poll. Please note this will only stop the client-side polling
+   * @deprecated Use abortSignal to stop polling instead.
+   */
+  stopPolling(): void;
+
+  /**
+   * Returns true if the poller is stopped.
+   * @deprecated Use abortSignal status to track this instead.
+   */
+  isStopped(): boolean;
+}
+
+/**
+ * Create the deprecated SimplePollerLike from PollerLike
+ * @param poller PollerLike to convert
+ * @returns SimplePollerLike
+ */
+export function getSimplePoller<TResult>(
+  poller: PollerLike<OperationState<TResult>, TResult>,
+): SimplePollerLike<OperationState<TResult>, TResult> {
+  const simplePoller: SimplePollerLike<OperationState<TResult>, TResult> = {
+    isDone() {
+      return poller.isDone;
+    },
+    isStopped() {
+      throw new Error("isStopped is deprecated. Use abortSignal status to track this instead.");
+    },
+    getOperationState() {
+      if (!poller.operationState) {
+        throw new Error(
+          "Operation state is not available. The poller may not have been started and you could await submitted() before calling getOperationState().",
+        );
+      }
+      return poller.operationState;
+    },
+    getResult() {
+      return poller.result;
+    },
+    toString() {
+      if (!poller.operationState) {
+        throw new Error(
+          "Operation state is not available. The poller may not have been started and you could await submitted() before calling getOperationState().",
+        );
+      }
+      return JSON.stringify({
+        state: poller.operationState,
+      });
+    },
+    stopPolling() {
+      throw new Error("stopPolling is deprecated. Use abortSignal to stop polling instead.");
+    },
+    onProgress: poller.onProgress,
+    poll: poller.poll,
+    pollUntilDone: poller.pollUntilDone,
+    serialize: poller.serialize,
+    submitted: poller.submitted,
+  };
+  return simplePoller;
+}"},{"filename":"sdk/horizondb/arm-horizondb/src/static-helpers/urlTemplate.ts","status":"added","additions":227,"changes":227,"patch":"@@ -0,0 +1,227 @@
+// Copyright (c) Microsoft Corporation.
+// Licensed under the MIT License.
+
+// ---------------------
+// interfaces
+// ---------------------
+interface ValueOptions {
+  isFirst: boolean; // is first value in the expression
+  op?: string; // operator
+  varValue?: any; // variable value
+  varName?: string; // variable name
+  modifier?: string; // modifier e.g *
+  reserved?: boolean; // if true we'll keep reserved words with not encoding
+}
+
+export interface UrlTemplateOptions {
+  // if set to true, reserved characters will not be encoded
+  allowReserved?: boolean;
+}
+
+// ---------------------
+// helpers
+// ---------------------
+function encodeComponent(val: string, reserved?: boolean, op?: string): string {
+  return (reserved ?? op === "+") || op === "#"
+    ? encodeReservedComponent(val)
+    : encodeRFC3986URIComponent(val);
+}
+
+function encodeReservedComponent(str: string): string {
+  return str
+    .split(/(%[0-9A-Fa-f]{2})/g)
+    .map((part) => (!/%[0-9A-Fa-f]/.test(part) ? encodeURI(part) : part))
+    .join("");
+}
+
+function encodeRFC3986URIComponent(str: string): string {
+  return encodeURIComponent(str).replace(
+    /[!'()*]/g,
+    (c) => `%${c.charCodeAt(0).toString(16).toUpperCase()}`,
+  );
+}
+
+function isDefined(val: any): boolean {
+  return val !== undefined && val !== null;
+}
+
+function getNamedAndIfEmpty(op?: string): [boolean, string] {
+  return [!!op && [";", "?", "&"].includes(op), !!op && ["?", "&"].includes(op) ? "=" : ""];
+}
+
+function getFirstOrSep(op?: string, isFirst = false): string {
+  if (isFirst) {
+    return !op || op === "+" ? "" : op;
+  } else if (!op || op === "+" || op === "#") {
+    return ",";
+  } else if (op === "?") {
+    return "&";
+  } else {
+    return op;
+  }
+}
+
+function getExpandedValue(option: ValueOptions): string {
+  let isFirst = option.isFirst;
+  const { op, varName, varValue: value, reserved } = option;
+  const vals: string[] = [];
+  const [named, ifEmpty] = getNamedAndIfEmpty(op);
+
+  if (Array.isArray(value)) {
+    for (const val of value.filter(isDefined)) {
+      // prepare the following parts: separator, varName, value
+      vals.push(`${getFirstOrSep(op, isFirst)}`);
+      if (named && varName) {
+        vals.push(`${encodeURIComponent(varName)}`);
+        if (val === "") {
+          vals.push(ifEmpty);
+        } else {
+          vals.push("=");
+        }
+      }
+      vals.push(encodeComponent(val, reserved, op));
+      isFirst = false;
+    }
+  } else if (typeof value === "object") {
+    for (const key of Object.keys(value)) {
+      const val = value[key];
+      if (!isDefined(val)) {
+        continue;
+      }
+      // prepare the following parts: separator, key, value
+      vals.push(`${getFirstOrSep(op, isFirst)}`);
+      if (key) {
+        vals.push(`${encodeURIComponent(key)}`);
+        if (named && val === "") {
+          vals.push(ifEmpty);
+        } else {
+          vals.push("=");
+        }
+      }
+      vals.push(encodeComponent(val, reserved, op));
+      isFirst = false;
+    }
+  }
+  return vals.join("");
+}
+
+function getNonExpandedValue(option: ValueOptions): string | undefined {
+  const { op, varName, varValue: value, isFirst, reserved } = option;
+  const vals: string[] = [];
+  const first = getFirstOrSep(op, isFirst);
+  const [named, ifEmpty] = getNamedAndIfEmpty(op);
+  if (named && varName) {
+    vals.push(encodeComponent(varName, reserved, op));
+    if (value === "") {
+      if (!ifEmpty) {
+        vals.push(ifEmpty);
+      }
+      return !vals.join("") ? undefined : `${first}${vals.join("")}`;
+    }
+    vals.push("=");
+  }
+
+  const items = [];
+  if (Array.isArray(value)) {
+    for (const val of value.filter(isDefined)) {
+      items.push(encodeComponent(val, reserved, op));
+    }
+  } else if (typeof value === "object") {
+    for (const key of Object.keys(value)) {
+      if (!isDefined(value[key])) {
+        continue;
+      }
+      items.push(encodeRFC3986URIComponent(key));
+      items.push(encodeComponent(value[key], reserved, op));
+    }
+  }
+  vals.push(items.join(","));
+  return !vals.join(",") ? undefined : `${first}${vals.join("")}`;
+}
+
+function getVarValue(option: ValueOptions): string | undefined {
+  const { op, varName, modifier, isFirst, reserved, varValue: value } = option;
+
+  if (!isDefined(value)) {
+    return undefined;
+  } else if (["string", "number", "boolean"].includes(typeof value)) {
+    let val = value.toString();
+    const [named, ifEmpty] = getNamedAndIfEmpty(op);
+    const vals: string[] = [getFirstOrSep(op, isFirst)];
+    if (named && varName) {
+      // No need to encode varName considering it is already encoded
+      vals.push(varName);
+      if (val === "") {
+        vals.push(ifEmpty);
+      } else {
+        vals.push("=");
+      }
+    }
+    if (modifier && modifier !== "*") {
+      val = val.substring(0, parseInt(modifier, 10));
+    }
+    vals.push(encodeComponent(val, reserved, op));
+    return vals.join("");
+  } else if (modifier === "*") {
+    return getExpandedValue(option);
+  } else {
+    return getNonExpandedValue(option);
+  }
+}
+
+// ---------------------------------------------------------------------------------------------------
+// This is an implementation of RFC 6570 URI Template: https://datatracker.ietf.org/doc/html/rfc6570.
+// ---------------------------------------------------------------------------------------------------
+export function expandUrlTemplate(
+  template: string,
+  context: Record<string, any>,
+  option?: UrlTemplateOptions,
+): string {
+  const result = template.replace(/\{([^{}]+)\}|([^{}]+)/g, (_, expr, text) => {
+    if (!expr) {
+      return encodeReservedComponent(text);
+    }
+    let op;
+    if (["+", "#", ".", "/", ";", "?", "&"].includes(expr[0])) {
+      op = expr[0];
+      expr = expr.slice(1);
+    }
+    const varList = expr.split(/,/g);
+    const innerResult = [];
+    for (const varSpec of varList) {
+      const varMatch = /([^:*]*)(?::(\d+)|(\*))?/.exec(varSpec);
+      if (!varMatch || !varMatch[1]) {
+        continue;
+      }
+      const varValue = getVarValue({
+        isFirst: innerResult.length === 0,
+        op,
+        varValue: context[varMatch[1]],
+        varName: varMatch[1],
+        modifier: varMatch[2] || varMatch[3],
+        reserved: option?.allowReserved,
+      });
+      if (varValue) {
+        innerResult.push(varValue);
+      }
+    }
+    return innerResult.join("");
+  });
+
+  return normalizeUnreserved(result);
+}
+
+/**
+ * Normalize an expanded URI by decoding percent-encoded unreserved characters.
+ * RFC 3986 unreserved: "-" / "." / "~"
+ */
+function normalizeUnreserved(uri: string): string {
+  return uri.replace(/%([0-9A-Fa-f]{2})/g, (match, hex) => {
+    const char = String.fromCharCode(parseInt(hex, 16));
+    // Decode only if it's unreserved
+    if (/[.~-]/.test(char)) {
+      return char;
+    }
+    return match; // leave other encodings intact
+  });
+}"},{"filename":"sdk/horizondb/arm-horizondb/test/public/sampleTest.spec.ts","status":"added","additions":28,"changes":28,"patch":"@@ -0,0 +1,28 @@
